Steps.DetectionScript:
$svc = Get-Service -Name wuauserv -ErrorAction SilentlyContinue
if (-not $svc) { return @{ Status = 'Failed'; Message = 'Windows Update service not found' } }
if ($svc.StartType -eq 'Disabled') { return @{ Status = 'Failed'; Message = 'Windows Update service is Disabled' } }
if ($svc.Status -eq 'Running' -or $svc.StartType -eq 'Manual') {
    return @{ Status = 'Passed'; Message = "wuauserv: $($svc.Status) / $($svc.StartType)" }
}
return @{ Status = 'Warning'; Message = "wuauserv: $($svc.Status) / $($svc.StartType)" }

$svc = Get-Service -Name BITS -ErrorAction SilentlyContinue
if (-not $svc) { return @{ Status = 'Failed'; Message = 'BITS service not found' } }
if ($svc.StartType -eq 'Disabled') { return @{ Status = 'Failed'; Message = 'BITS is Disabled' } }
return @{ Status = 'Passed'; Message = "BITS: $($svc.Status) / $($svc.StartType)" }

$pendingPaths = @(
    'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\WindowsUpdate\Auto Update\RebootRequired',
    'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Component Based Servicing\RebootPending',
    'HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager'
)
$pending = $false
if (Test-Path $pendingPaths[0]) { $pending = $true }
if (Test-Path $pendingPaths[1]) { $pending = $true }
$cbsKey = Get-ItemProperty -Path $pendingPaths[2] -Name PendingFileRenameOperations -ErrorAction SilentlyContinue
if ($cbsKey) { $pending = $true }
if ($pending) { return @{ Status = 'Warning'; Message = 'System has a pending reboot' } }
return @{ Status = 'Passed'; Message = 'No pending reboot detected' }

$wuPolicyPath = 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate'
$auPolicyPath = "$wuPolicyPath\AU"
$wsusServer = (Get-ItemProperty -Path $wuPolicyPath -Name WUServer -ErrorAction SilentlyContinue).WUServer
$useWUSS = (Get-ItemProperty -Path $auPolicyPath -Name UseWUServer -ErrorAction SilentlyContinue).UseWUServer
if ($wsusServer -and $useWUSS -eq 1) {
    return @{ Status = 'Passed'; Message = "Managed by: $wsusServer" }
}
if ($wsusServer -and $useWUSS -ne 1) {
    return @{ Status = 'Warning'; Message = 'WSUS server set but UseWUServer is disabled' }
}
return @{ Status = 'Warning'; Message = 'No WSUS/SCCM policy found — using Windows Update directly' }

try {
    $session = New-Object -ComObject 'Microsoft.Update.Session' -ErrorAction Stop
    $searcher = $session.CreateUpdateSearcher()
    $count = $searcher.GetTotalHistoryCount()
    if ($count -eq 0) { return @{ Status = 'Warning'; Message = 'No update history found' } }
    $history = $searcher.QueryHistory(0, [Math]::Min($count, 50))
    $lastSuccess = $history | Where-Object { $_.ResultCode -eq 2 } | Select-Object -First 1
    if (-not $lastSuccess) { return @{ Status = 'Warning'; Message = 'No successful updates in recent history' } }
    $days = [int]((Get-Date) - $lastSuccess.Date).TotalDays
    $dateStr = $lastSuccess.Date.ToString('yyyy-MM-dd')
    if ($days -gt 60) { return @{ Status = 'Warning'; Message = "Last update $days days ago ($dateStr)" } }
    return @{ Status = 'Passed'; Message = "Last update: $dateStr ($days days ago)" }
} catch {
    return @{ Status = 'Warning'; Message = 'Unable to query update history' }
}

$datastore = "$env:SystemRoot\SoftwareDistribution\DataStore"
$db = Join-Path $datastore 'DataStore.edb'
if (-not (Test-Path $datastore)) { return @{ Status = 'Warning'; Message = 'DataStore folder missing' } }
if (-not (Test-Path $db)) { return @{ Status = 'Warning'; Message = 'DataStore.edb missing — may rebuild on next update cycle' } }
$size = [math]::Round((Get-Item $db).Length / 1MB, 1)
if ($size -gt 500) { return @{ Status = 'Warning'; Message = "DataStore.edb is very large ($($size)MB) — may be bloated" } }
return @{ Status = 'Passed'; Message = "DataStore.edb present ($($size)MB)" }

$svc = Get-Service -Name CryptSvc -ErrorAction SilentlyContinue
if (-not $svc) { return @{ Status = 'Failed'; Message = 'CryptSvc not found' } }
if ($svc.Status -eq 'Running') { return @{ Status = 'Passed'; Message = 'CryptSvc is running' } }
return @{ Status = 'Failed'; Message = "CryptSvc is $($svc.Status)" }

$drive = Get-PSDrive -Name C -ErrorAction SilentlyContinue
if (-not $drive) { return @{ Status = 'Warning'; Message = 'Unable to check C: drive' } }
$freeGB = [math]::Round($drive.Free / 1GB, 1)
if ($freeGB -lt 5) { return @{ Status = 'Failed'; Message = "Only $($freeGB)GB free on C: — updates need at least 5GB" } }
if ($freeGB -lt 10) { return @{ Status = 'Warning'; Message = "$($freeGB)GB free — low, may affect large updates" } }
return @{ Status = 'Passed'; Message = "$($freeGB)GB free on C:" }
